svg.script:

// Physics Variables
let state = {
    'pitch': 10,   // 0 to 25 degrees
    'speed': 100   // 0 to 200 mph
};

// Animation States
let lastTime = 0;
let windOffset = 0;
let isStalled = false;

// Slider Configurations
const SLIDER_WIDTH = 350;
let activeSlider = null;

const sliderConfig = {
    'pitch': { min: 0, max: 25 },
    'speed': { min: 0, max: 200 }
};

const CRITICAL_ANGLE = 15;

function initSimulation() {
    updateVisuals();
    requestAnimationFrame(animationLoop);
}

// Drag Handling
function getClientX(evt) {
    if (evt.touches && evt.touches.length > 0) return evt.touches[0].clientX;
    if (evt.changedTouches && evt.changedTouches.length > 0) return evt.changedTouches[0].clientX;
    return evt.clientX;
}
function getClientY(evt) {
    if (evt.touches && evt.touches.length > 0) return evt.touches[0].clientY;
    if (evt.changedTouches && evt.changedTouches.length > 0) return evt.changedTouches[0].clientY;
    return evt.clientY;
}

function startDrag(evt, id) {
    activeSlider = id;
    updateDrag(evt);
}
function startDragTouch(evt, id) {
    evt.preventDefault();
    activeSlider = id;
    updateDrag(evt);
}

function onMouseMove(evt) {
    if (activeSlider) updateDrag(evt);
}
function onMouseUp(evt) {
    activeSlider = null;
}
function onTouchMove(evt) {
    if (activeSlider) { evt.preventDefault(); updateDrag(evt); }
}
function onTouchEnd(evt) {
    activeSlider = null;
}

function updateDrag(evt) {
    const svg = document.getElementById('main-svg');
    const pt = svg.createSVGPoint();
    pt.x = getClientX(evt);
    pt.y = getClientY(evt);
    const svgP = pt.matrixTransform(svg.getScreenCTM().inverse());

    // Sliders track starts at x=770
    let localX = svgP.x - 770;
    if (localX < 0) localX = 0;
    if (localX > SLIDER_WIDTH) localX = SLIDER_WIDTH;

    const conf = sliderConfig[activeSlider];
    state[activeSlider] = conf.min + (localX / SLIDER_WIDTH) * (conf.max - conf.min);

    // Update Slider Visuals
    document.getElementById('track-' + activeSlider).setAttribute('x2', localX);
    document.getElementById('thumb-' + activeSlider).setAttribute('cx', localX);

    let valSuffix = activeSlider === 'pitch' ? '°' : ' mph';
    document.getElementById('slider-val-' + activeSlider).textContent = Math.round(state[activeSlider]) + valSuffix;

    updateVisuals();
}

function updateVisuals() {
    const pitch = state.pitch;
    const speed = state.speed;

    isStalled = pitch > CRITICAL_ANGLE;

    // --- Physics Calculations ---
    // Lift = Coefficient * V^2 * AoA
    const speedFactor = speed / 100; // Normalized
    let liftAmount = 0;
    let dragAmount = 0;

    if (!isStalled) {
        // Normal Flight Regime
        liftAmount = speedFactor * speedFactor * (pitch * 250);
        dragAmount = speedFactor * speedFactor * (pitch * pitch * 3); // Parasitic + Induced drag
    } else {
        // STALLED Regime
        // Lift drops sharply as angle increases past critical
        const stallPenalty = Math.max(0.1, 1 - ((pitch - CRITICAL_ANGLE) * 0.15));
        liftAmount = speedFactor * speedFactor * (CRITICAL_ANGLE * 250) * stallPenalty;

        // Drag spikes massively due to flow separation
        const dragSpike = 1 + ((pitch - CRITICAL_ANGLE) * 1.5);
        dragAmount = speedFactor * speedFactor * (CRITICAL_ANGLE * CRITICAL_ANGLE * 3) * dragSpike;
    }

    // Update UI Metrics
    document.getElementById('metric-aoa').textContent = Math.round(pitch * 10)/10 + '°';

    if (isStalled) {
        document.getElementById('metric-aoa').setAttribute('fill', '#ef4444');
        document.getElementById('metric-lift').setAttribute('fill', '#ef4444');
        document.getElementById('metric-state').textContent = "STALLED (SEPARATED)";
        document.getElementById('metric-state').setAttribute('fill', '#ef4444');
    } else {
        document.getElementById('metric-aoa').setAttribute('fill', '#fbbf24');
        document.getElementById('metric-lift').setAttribute('fill', '#10b981');
        document.getElementById('metric-state').textContent = "SMOOTH / ATTACHED";
        document.getElementById('metric-state').setAttribute('fill', '#38bdf8');
    }

    document.getElementById('metric-lift').textContent = Math.round(liftAmount) + ' lbs';
    document.getElementById('metric-drag').textContent = Math.round(dragAmount) + ' lbs';

    // --- Visual Updates ---

    // 1. Rotate Airfoil (Center of pressure is at x=-50, y=0)
    document.getElementById('airfoil-model').setAttribute('transform', `rotate(${-pitch})`);

    // 2. Draw Angle of Attack Arc
    const rad = (pitch * Math.PI) / 180;
    const arcX = -150 * Math.cos(rad);
    const arcY = -150 * Math.sin(rad);
    if (pitch > 0) {
        document.getElementById('aoa-arc').setAttribute('d', `M -150,0 A 150 150 0 0 1 ${arcX},${arcY}`);
    } else {
        document.getElementById('aoa-arc').setAttribute('d', `M -150,0 L -150,0`); // Hide if 0
    }

    // Move AoA label to follow the arc roughly
    document.getElementById('aoa-label').setAttribute('y', Math.min(-20, arcY - 10));

    // 3. Scale Vectors
    // Because we rotate the whole model, we must un-rotate the vectors so Lift points perfectly UP 
    // relative to the wind tunnel, and drag points perfectly BACK.
    document.getElementById('vec-lift-group').setAttribute('transform', `rotate(${pitch})`);
    document.getElementById('vec-drag-group').setAttribute('transform', `rotate(${pitch})`);

    const liftPixels = Math.max(5, liftAmount * 0.025);
    document.getElementById('vec-lift').setAttribute('y2', -liftPixels);
    document.getElementById('lbl-lift').setAttribute('y', -liftPixels - 15);

    const dragPixels = Math.max(5, dragAmount * 0.05);
    document.getElementById('vec-drag').setAttribute('x2', dragPixels);
    document.getElementById('lbl-drag').setAttribute('x', dragPixels + 15);
}

// 60fps Animation Loop
function animationLoop(timestamp) {
    if (!lastTime) lastTime = timestamp;
    const dt = timestamp - lastTime || 16;
    lastTime = timestamp;

    const timeSecs = timestamp / 1000;

    // 1. Animate Wind Stream Flow
    const windSpeed = (state.speed * 0.2) + 1; // Base flow even at 0 for visual tracking
    windOffset -= windSpeed;

    const windStreams = document.getElementsByClassName('wind-stream');
    for (let i = 0; i < windStreams.length; i++) {
        windStreams[i].setAttribute('stroke-dashoffset', windOffset);
    }

    // 2. Handle Turbulence / Flow Separation
    const topWindSmooth = document.getElementById('wind-top-smooth');
    const topWindTurbulent1 = document.getElementById('wind-turbulent-1');
    const topWindTurbulent2 = document.getElementById('wind-turbulent-2');
    const stallWarning = document.getElementById('stall-warning-text');

    if (isStalled) {
        // Hide smooth top wind, show turbulent streams
        topWindSmooth.setAttribute('display', 'none');
        topWindTurbulent1.setAttribute('display', 'block');
        topWindTurbulent2.setAttribute('display', 'block');

        // Generate Chaotic paths math
        // Flow hits the leading edge and then detaches upward in swirling vortices

        // Stream 1
        const v1 = Math.sin(timeSecs * 15) * 40;
        const v2 = Math.cos(timeSecs * 12) * 60;
        const v3 = Math.sin(timeSecs * 8) * 80;
        const path1 = `M -400,-50 L -120,-50 C -50,${-50 + v1} 50,${-100 + v2} 150,${-50 + v3} S 300,${-80 + v1} 400,-50`;
        topWindTurbulent1.setAttribute('d', path1);
        topWindTurbulent1.setAttribute('stroke-dashoffset', windOffset * 1.5); // Moves faster/erratic
        topWindTurbulent1.setAttribute('stroke-dasharray', '20 40');

        // Stream 2
        const v4 = Math.cos(timeSecs * 18) * 50;
        const v5 = Math.sin(timeSecs * 10) * 70;
        const path2 = `M -400,-50 L -120,-50 C -20,${-80 + v4} 80,${-20 + v5} 180,${-100 + v4} S 350,${-40 + v5} 400,-100`;
        topWindTurbulent2.setAttribute('d', path2);
        topWindTurbulent2.setAttribute('stroke-dashoffset', windOffset * 1.2);
        topWindTurbulent2.setAttribute('stroke-dasharray', '10 30');

        // Flash STALL WARNING text
        stallWarning.setAttribute('opacity', (Math.sin(timeSecs * 20) + 1) / 2);

    } else {
        // Attached, smooth flow
        topWindTurbulent1.setAttribute('display', 'none');
        topWindTurbulent2.setAttribute('display', 'none');
        stallWarning.setAttribute('opacity', 0);
        topWindSmooth.setAttribute('display', 'block');

        // The smooth wind naturally deflects slightly downwards due to downwash
        const downwash = state.pitch * 3;
        topWindSmooth.setAttribute('d', `M -400,-50 C -100,-50 0,${-50 + downwash} 400,${-50 + downwash * 2}`);
    }

    requestAnimationFrame(animationLoop);
}
